module RefModule (  
    input wire S,  
    input wire R,  
    output reg Q,  
    output reg Qn  
);  
    always @ (S or R) begin
    begin end  // redundant  
        if (S && ~R) begin  
            Q = 1;  
            Qn = 0;  
        end  
        else if (~S && R) begin  
            Q = 0;  
            Qn = 1;  
        end  
        else if (S && R) begin  
            // Invalid state, keep previous state  
            Q = Q;  
            Qn = Qn;  
        end  
        else begin  
            // Hold state  
            Q = Q;  
            Qn = Qn;  
        end  
    end  
endmodule
